/**
 * Create a handler that returns a JSON response.
 */
export function createJsonHandler(data: unknown, status = 200) {
  return defineEventHandler(() => {
    return new Response(JSON.stringify(data), {
      status,
      headers: { 'content-type': 'application/json' },
    });
  });
}

import { describe, it, expect } from 'vitest';
import { defineEventHandler } from '../src';

describe('defineEventHandler', () => {
  it('creates a handler function', () => {
    const handler = defineEventHandler(() => 'hello');
    expect(typeof handler).toBe('function');
  });

  it('handler returns expected value', async () => {
    const handler = defineEventHandler(() => ({ ok: true }));
    expect(typeof handler).toBe('function');
  });
});
